function ContactInfo({ c }: { c: typeof content.contacto }) {
  return (
    <section className="section-padding" style={{ background: "#0d0d0d" }}>
      <div className="container" style={{ maxWidth: "600px" }}>
        <div style={{ display: "flex", flexDirection: "column", gap: "1rem", marginBottom: "3rem" }}>
          {c.info.map((item, i) => (
            <a key={i} href={item.link} target="_blank" rel="noopener noreferrer" className="glass-card" style={{ padding: "1.25rem 1.5rem", display: "flex", alignItems: "center", gap: "1rem", textDecoration: "none", transition: "all 0.2s" }}
              onMouseEnter={(e) => { e.currentTarget.style.borderColor = "rgba(212,168,75,0.4)"; e.currentTarget.style.transform = "translateX(4px)"; }}
              onMouseLeave={(e) => { e.currentTarget.style.borderColor = "rgba(255,255,255,0.1)"; e.currentTarget.style.transform = "translateX(0)"; }}>
              <span style={{ fontSize: "1.5rem" }}>{item.icon}</span>
              <div>
                <div style={{ color: "#888", fontSize: "0.75rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.05em" }}>{item.label}</div>
                <div style={{ color: "#f0f0f0", fontWeight: 600 }}>{item.value}</div>
              </div>
            </a>
          ))}
        </div>
      </div>
    </section>
  );
}

function ContactForm({ c }: { c: typeof content.contacto }) {
  const [sent, setSent] = useState(false);
  const f = c.formFields;
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const form = e.target as HTMLFormElement;
    const name = (form.elements.namedItem("name") as HTMLInputElement).value;
    const email = (form.elements.namedItem("email") as HTMLInputElement).value;
    const message = (form.elements.namedItem("message") as HTMLTextAreaElement).value;
    const body = encodeURIComponent(`Nombre: ${name}\nEmail: ${email}\n\n${message}`);
    window.open(`https://wa.me/${content.site.whatsapp.replace(/[^0-9]/g, "")}?text=${body}`, "_blank");
    setSent(true);
  };
  return (
    <section style={{ padding: "0 0 5rem", background: "#111" }}>
      <div className="container" style={{ maxWidth: "600px" }}>
        <p style={{ color: "#999", textAlign: "center", marginBottom: "2rem" }}>{c.formIntro}</p>
        {sent ? (
          <div className="glass-card" style={{ padding: "2rem", textAlign: "center", border: "1px solid rgba(212,168,75,0.3)" }}>
            <div style={{ fontSize: "2.5rem", marginBottom: "1rem" }}>✅</div>
            <p style={{ color: "#f0f0f0" }}>Gracias por escribirnos. Te respondemos por WhatsApp.</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="glass-card" style={{ padding: "2rem", display: "flex", flexDirection: "column", gap: "1.25rem" }}>
            <input type="text" name="name" placeholder={f.name} required style={{ width: "100%", padding: "0.875rem 1rem", borderRadius: "0.5rem", border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.05)", color: "#f0f0f0", fontSize: "0.9375rem", outline: "none" }} />
            <input type="email" name="email" placeholder={f.email} required style={{ width: "100%", padding: "0.875rem 1rem", borderRadius: "0.5rem", border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.05)", color: "#f0f0f0", fontSize: "0.9375rem", outline: "none" }} />
            <textarea name="message" placeholder={f.message} required rows={5} style={{ width: "100%", padding: "0.875rem 1rem", borderRadius: "0.5rem", border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.05)", color: "#f0f0f0", fontSize: "0.9375rem", outline: "none", resize: "vertical" }} />
            <button type="submit" className="btn-gold" style={{ border: "none", cursor: "pointer", textAlign: "center" }}>{f.submit}</button>
          </form>
        )}
      </div>
    </section>
  );
}
