{"content": "@import "tailwindcss";

@theme {
  --color-primary: #1a3a2a;
  --color-primary-light: #2d5a3f;
  --color-secondary: #d4a84b;
  --color-secondary-hover: #c49a3f;
  --color-background: #0d0d0d;
  --color-surface: #1a1a1a;
  --color-surface-light: #262626;
  --color-text: #f0f0f0;
  --color-text-muted: #999999;
  --color-accent: #e63946;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

html { scroll-behavior: smooth; }

body {
  background-color: var(--color-background);
  color: var(--color-text);
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
  -webkit-font-smoothing: antialiased;
  padding-top: 4rem;
}

.container { max-width: 1200px; margin: 0 auto; padding: 0 1.5rem; }

.glass-card {
  background: rgba(255, 255, 255, 0.03);
  backdrop-filter: blur(16px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 1rem;
}

.gradient-text {
  background: linear-gradient(135deg, #d4a84b, #f0d68a);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.section-padding { padding: 5rem 0; }

.page-hero {
  min-height: 50vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 6rem 0 3rem;
}

@media (max-width: 768px) {
  .section-padding { padding: 3rem 0; }
  .page-hero { min-height: 40vh; padding: 5rem 0 2rem; }
}

/* Cards */
.card {
  background: #1a1a1a;
  border: 1px solid rgba(255,255,255,0.06);
  border-radius: 1rem;
  padding: 2rem;
  text-align: center;
  transition: transform 0.2s;
}

/* FAQ items */
.faq-item {
  background: #1a1a1a;
  border: 1px solid rgba(255,255,255,0.06);
  border-radius: 0.75rem;
  padding: 1.25rem;
  cursor: pointer;
}

/* Buttons */
.btn-gold {
  padding: 0.875rem 2rem;
  border-radius: 0.5rem;
  background: #d4a84b;
  color: #0d0d0d;
  font-weight: 700;
  font-size: 0.9375rem;
  text-decoration: none;
  transition: transform 0.2s, background 0.2s;
}
.btn-gold:hover { background: #c49a3f; transform: scale(1.02); }

.btn-outline {
  padding: 0.875rem 2rem;
  border-radius: 0.5rem;
  background: transparent;
  border: 1px solid rgba(255,255,255,0.3);
  color: #f0f0f0;
  font-weight: 600;
  font-size: 0.9375rem;
  text-decoration: none;
  transition: transform 0.2s;
  display: inline-block;
}
.btn-outline:hover { transform: scale(1.02); }

/* Form inputs */
input:focus, textarea:focus {
  border-color: #d4a84b !important;
  box-shadow: 0 0 0 2px rgba(212,168,75,0.15);
}
